# OpenAI-compatible gateway helpers. Foreign models use the NewAPI relay from
# the zhuzuo project; DeepSeek is kept on the official API.
def foreign_model_base_url() -> str:
    base_url = (
        os.environ.get("NEWAPI_BASE_URL", "")
        or os.environ.get("FOREIGN_MODEL_BASE_URL", "")
        or DEFAULT_FOREIGN_MODEL_BASE_URL
    ).rstrip("/")
    base_url = base_url.replace("greatwallink.top", "greatwalllink.top")
    if not base_url.endswith("/v1"):
        base_url = base_url.rstrip("/") + "/v1"
    return base_url


def deepseek_base_url() -> str:
    return (os.environ.get("DEEPSEEK_BASE_URL", "") or DEFAULT_DEEPSEEK_BASE_URL).rstrip("/")


def requests_post_no_proxy(url: str, **kwargs):
    session = requests.Session()
    session.trust_env = False
    try:
        return session.post(url, **kwargs)
    finally:
        session.close()


# OpenAI-compatible gateways PDF direct-upload helpers (ChatShare / Grok best-effort).
def _extract_openai_compatible_text_response(data) -> str:
    try:
        if not isinstance(data, dict):
            return ""
        direct = data.get("output_text") or data.get("text")
        if direct:
            return str(direct).strip()
        choices = data.get("choices") or []
        if choices:
            first = choices[0] or {}
            msg = first.get("message") or {}
            content = msg.get("content") or first.get("text") or ""
            if isinstance(content, list):
                parts = []
                for part in content:
                    if isinstance(part, dict):
                        parts.append(str(part.get("text") or part.get("content") or ""))
                    else:
                        parts.append(str(part))
                return "".join(parts).strip()
            return str(content).strip()
        output = data.get("output") or []
        if isinstance(output, list):
            parts = []
            for item in output:
                if isinstance(item, dict):
                    content = item.get("content") or []
                    if isinstance(content, list):
                        for part in content:
                            if isinstance(part, dict):
                                parts.append(str(part.get("text") or part.get("content") or ""))
                            else:
                                parts.append(str(part))
            return "".join(parts).strip()
    except Exception:
        return ""
    return ""


def _extract_chat_completion_content(response) -> str:
    if isinstance(response, str):
        return response.strip()
    if isinstance(response, dict):
        return _extract_openai_compatible_text_response(response)
    try:
        return str((response.choices[0].message.content or "")).strip()
    except Exception:
        return ""


def _response_to_dict(response) -> dict:
    if isinstance(response, dict):
        return response
    for attr in ("model_dump", "dict"):
        try:
            fn = getattr(response, attr, None)
            if callable(fn):
                data = fn()
                if isinstance(data, dict):
                    return data
        except Exception:
            pass
    try:
        fn = getattr(response, "model_dump_json", None)
        if callable(fn):
            text = fn()
            if text:
                data = json.loads(text)
                return data if isinstance(data, dict) else {}
    except Exception:
        pass
    return {}


def _extract_response_text(response) -> str:
    direct = getattr(response, "output_text", "") or ""
    if str(direct).strip():
        return str(direct).strip()
    return _extract_openai_compatible_text_response(_response_to_dict(response))


def _openai_compatible_upload_pdf_file(base_url: str, api_key: str, pdf_path: str, logger, provider_name: str) -> str:
    base_url = str(base_url or "").rstrip("/")
    if not base_url:
        logger(f"❌ {provider_name} PDF 直传失败：API Base URL 为空。")
        return ""
    if not pdf_path or not os.path.exists(pdf_path):
        logger(f"❌ {provider_name} PDF 直传失败：章节 PDF 文件不存在。")
        return ""
    purpose = os.environ.get("OPENAI_COMPAT_PDF_UPLOAD_PURPOSE") or os.environ.get("CHAT_COMPLETION_PDF_UPLOAD_PURPOSE") or globals().get("OPENAI_PDF_UPLOAD_PURPOSE", "assistants")
    headers = {"Authorization": f"Bearer {api_key}"}
    upload_url = f"{base_url}/files"
    try:
        logger(f"📎 正在把章节 PDF 上传给 {provider_name}：{os.path.basename(pdf_path)}")
        with AsciiUploadCopy(pdf_path, suffix=".pdf", logger=logger) as upload_file:
            with open(upload_file.path, "rb") as f:
                resp = requests.post(
                    upload_url,
                    headers=headers,
                    data={"purpose": purpose},
                    files={"file": (upload_file.upload_name, f, "application/pdf")},
                    timeout=600,
                )
        if resp.status_code >= 400:
            logger(f"❌ {provider_name} PDF 上传失败：HTTP {resp.status_code}；{resp.text[:260]}")
            return ""
        data = resp.json()
        file_id = str(data.get("id") or data.get("file_id") or ((data.get("data") or {}).get("id") if isinstance(data.get("data"), dict) else "") or "").strip()
        if not file_id:
            logger(f"❌ {provider_name} PDF 上传后未返回 file_id：{str(data)[:220]}")
            return ""
        logger(f"✅ {provider_name} PDF 已上传，file_id={file_id[:16]}...")
        return file_id
    except Exception as e:
        logger(f"❌ {provider_name} PDF 上传请求出错：{str(e)[:220]}")
        return ""


