GEMINI_MAX_RETRIES = int(os.environ.get("GEMINI_MAX_RETRIES", "6"))
GEMINI_RETRY_BASE_SECONDS = float(os.environ.get("GEMINI_RETRY_BASE_SECONDS", "2.0"))
GEMINI_TEXT_MAX_OUTPUT_TOKENS = int(os.environ.get("GEMINI_TEXT_MAX_OUTPUT_TOKENS", "18000" if TOKEN_SAVER_MODE else "24576"))
GEMINI_TIMEOUT_MS = int(os.environ.get("GEMINI_TIMEOUT_MS", "600000"))

# 记录最近一次 Gemini 失败类型，便于上层自动回退到 GPT / Grok。
LAST_GEMINI_FAILURE_KIND = ""
LAST_GEMINI_FAILURE_MESSAGE = ""


def set_gemini_failure(kind: str, message: str = ""):
    global LAST_GEMINI_FAILURE_KIND, LAST_GEMINI_FAILURE_MESSAGE
    LAST_GEMINI_FAILURE_KIND = kind or ""
    LAST_GEMINI_FAILURE_MESSAGE = (message or "")[:300]


def clear_gemini_failure():
    set_gemini_failure("", "")


def gemini_failure_can_fallback() -> bool:
    return LAST_GEMINI_FAILURE_KIND in {"retryable", "unsupported_location", "empty_response"}


def compute_gemini_backoff_seconds(attempt: int) -> float:
    # 指数退避 + 少量抖动，避免连续请求撞上同一波服务端/网络波动。
    return min(60.0, GEMINI_RETRY_BASE_SECONDS * (2 ** (attempt - 1)) + random.uniform(0.2, 1.8))


def is_gemini_unsupported_location_error(err: Exception) -> bool:
    """Gemini 地区/账号位置不支持：这是 400 FAILED_PRECONDITION，不应重试。"""
    msg = str(err).lower()
    return (
        "failed_precondition" in msg
        and "location" in msg
        and "not supported" in msg
    ) or "user location is not supported for the api use" in msg


def is_non_retryable_gemini_error(err: Exception) -> bool:
    """不适合重试的 Gemini 错误。"""
    msg = str(err).lower()
    non_retryable_keywords = [
        "failed_precondition",
        "user location is not supported",
        "location is not supported",
        "billing",
        "quota project",
        "permission denied",
        "api key not valid",
        "unauthorized",
        "invalid argument",
    ]
    return any(k in msg for k in non_retryable_keywords)


def is_retryable_gemini_error(err: Exception) -> bool:
    """判断 Gemini 请求是否属于临时网络/服务端错误，可安全重试。"""
    if is_non_retryable_gemini_error(err):
        return False
    msg = str(err).lower()
    retry_keywords = [
        "server disconnected",
        "remote protocol",
        "connection reset",
        "connection aborted",
        "connection closed",
        "timeout",
        "timed out",
        "deadline",
        "temporarily unavailable",
        "unavailable",
        "internal",
        "bad gateway",
        "service unavailable",
        "gateway timeout",
        "502",
        "503",
        "504",
        "429",
        "rate limit",
        "resource exhausted",
    ]
    return any(k in msg for k in retry_keywords)


def log_gemini_unsupported_location(logger, *, task_name="Gemini API"):
    logger(f"❌ {task_name} 当前不可用：Gemini 返回 400 FAILED_PRECONDITION，提示当前账号或网络出口所在地区不支持 API 调用。")
    logger("这不是临时断连，自动重试不会解决。请将该步骤模型切换为 GPT-5.5 / GPT Image 2 或 Grok 4.2，或改用一个 Gemini API 支持的账号、项目、结算地区和网络出口。")


def build_gemini_client(genai_module, types_module=None):
    """创建 Gemini client；SDK 支持 http_options 时设置更长超时，否则回退普通 client。"""
    api_key = sanitize_gemini_api_key(os.environ.get("GEMINI_API_KEY", ""))
    # 实际 key 由调用方传入 client 构造时覆盖；这里只保留函数结构，避免全局硬编码。
    raise RuntimeError("build_gemini_client should be called with api_key via build_gemini_client_with_key")


def build_gemini_client_with_key(genai_module, api_key: str, types_module=None):
    try:
        if types_module is not None and hasattr(types_module, "HttpOptions"):
            return genai_module.Client(
                api_key=api_key,
                http_options=types_module.HttpOptions(timeout=GEMINI_TIMEOUT_MS),
            )
    except Exception:
        pass
    return genai_module.Client(api_key=api_key)


class GeminiApiClient:
    """基于 Google GenAI SDK 的 Gemini 3.1 Pro Preview 文本生成客户端，带重试容错。"""

    MODEL_NAME = os.environ.get("GEMINI_TEXT_MODEL", "gemini-3.1-pro-preview")

    @staticmethod
    def _call_generate_content(client, types, prompt: str, system_instruction: str, model_name: str = ""):
        if types is not None:
            config = types.GenerateContentConfig(
                system_instruction=system_instruction,
                temperature=0.3,
                max_output_tokens=GEMINI_TEXT_MAX_OUTPUT_TOKENS,
            )
            return client.models.generate_content(
                model=model_name or GeminiApiClient.MODEL_NAME,
                contents=prompt,
                config=config,
            )
        return client.models.generate_content(
            model=model_name or GeminiApiClient.MODEL_NAME,
            contents=f"{system_instruction}\n\n{prompt}",
        )

    @staticmethod
    def generate_text(api_key: str, prompt: str, logger, check_cancel=None, model_name: str = "") -> str:
        clear_gemini_failure()
        api_key = sanitize_gemini_api_key(api_key)
        if not is_valid_gemini_api_key(api_key):
            set_gemini_failure("invalid_key", "Gemini API Key 格式不正确")
            logger("❌ Gemini API Key 格式不正确：请确认只粘贴 GEMINI_API_KEY，不要包含 Bearer、空格、换行或多余字符。")
            return ""
        if check_cancel and check_cancel():
            return ""
        requested_model = str(model_name or "").strip()
        resolved_model = requested_model or GeminiApiClient.MODEL_NAME
        if "gemini_model_for_text_engine" in globals():
            resolved_model = gemini_model_for_text_engine(requested_model) if requested_model else GeminiApiClient.MODEL_NAME
        url = f"{foreign_model_base_url()}/chat/completions"
        headers = {"Content-Type": "application/json", "Authorization": f"Bearer {api_key}"}
        payload = {
            "model": resolved_model,
            "messages": [{"role": "user", "content": prompt}],
            "temperature": 0.3,
            "max_tokens": GEMINI_TEXT_MAX_OUTPUT_TOKENS,
        }
        last_err = ""
        for attempt in range(1, GEMINI_MAX_RETRIES + 1):
            if check_cancel and check_cancel():
                return ""
            try:
                if attempt == 1:
                    logger(f"🌐 正在通过中转站请求 Gemini {resolved_model}...")
                else:
                    logger(f"🔁 Gemini 文本请求第 {attempt}/{GEMINI_MAX_RETRIES} 次重试...")
                response = requests_post_no_proxy(url, headers=headers, json=payload, timeout=300)
                response.raise_for_status()
                if check_cancel and check_cancel():
                    return ""
                result = _extract_openai_compatible_text_response(response.json()).strip()
                if result:
                    clear_gemini_failure()
                    return result
                last_err = "Gemini 返回为空文本"
                set_gemini_failure("empty_response", last_err)
                raise RuntimeError(last_err)
            except Exception as e:
                err = str(e)
                last_err = err
                err_lower = err.lower()
                if is_gemini_unsupported_location_error(e):
                    set_gemini_failure("unsupported_location", err)
                    log_gemini_unsupported_location(logger, task_name="Gemini 文本 API")
                    return ""
                if "api key" in err_lower or "permission" in err_lower or "unauthorized" in err_lower:
                    set_gemini_failure("invalid_key_or_permission", err)
                    logger("❌ Gemini API Key 无效或权限不足。请确认 GEMINI_API_KEY 是否正确，并确认账号可用该模型。")
                    return ""
                if "not found" in err_lower or "model" in err_lower:
                    set_gemini_failure("model_unavailable", err)
                    logger(f"❌ Gemini 模型请求失败：请确认模型名 {resolved_model} 在当前账号/地区可用。错误：{err[:140]}")
                    return ""
                if is_non_retryable_gemini_error(e):
                    set_gemini_failure("non_retryable", err)
                    logger(f"❌ Gemini 文本 API 返回不可重试错误：{err[:180]}")
                    logger("建议：不要继续重试；请切换到 GPT-5.5 / GPT-5.4 mini / Grok 4.2，或更换支持 Gemini API 的账号、项目和网络环境。")
                    return ""
                if is_retryable_gemini_error(e):
                    set_gemini_failure("retryable", err)
                    if attempt < GEMINI_MAX_RETRIES:
                        wait_s = compute_gemini_backoff_seconds(attempt)
                        logger(f"⚠️ Gemini 连接临时中断：{err[:120]}；{wait_s:.0f}s 后自动重试。")
                        time.sleep(wait_s)
                        continue
                    logger(f"❌ Gemini 连续 {GEMINI_MAX_RETRIES} 次临时断连，已停止继续重试：{err[:180]}")
                    break
                set_gemini_failure("unknown", err)
                logger(f"❌ Gemini API 请求出错: {err[:180]}")
                break
        logger("建议：稍后重跑当前步骤；如果已填写 OpenAI 或 Grok Key，程序会尝试自动回退到 GPT-5.5 / Grok 继续当前文本步骤。")
        return ""



# 给 Gemini 增加 PDF 附件直传能力。
def _gemini_generate_text_with_pdf(api_key: str, prompt: str, pdf_path: str, logger, check_cancel=None, model_name: str = "") -> str:
    clear_gemini_failure()
    api_key = sanitize_gemini_api_key(api_key)
    if not is_valid_gemini_api_key(api_key):
        set_gemini_failure("invalid_key", "Gemini API Key 格式不正确")
        logger("❌ Gemini API Key 格式不正确，无法上传 PDF。")
        return ""
    if not pdf_path or not os.path.exists(pdf_path):
        logger("❌ Gemini PDF 直传失败：章节 PDF 文件不存在。")
        return ""
    if check_cancel and check_cancel():
        return ""
    try:
        from google import genai
        try:
            from google.genai import types
        except Exception:
            types = None
    except Exception:
        logger("❌ 缺少 google-genai 依赖。请先运行：pip install google-genai --upgrade")
        return ""
    system_instruction = ""
    requested_model = str(model_name or "").strip()
    resolved_model = requested_model or GeminiApiClient.MODEL_NAME
    if "gemini_model_for_text_engine" in globals():
        resolved_model = gemini_model_for_text_engine(requested_model) if requested_model else GeminiApiClient.MODEL_NAME
    last_err = ""
    for attempt in range(1, GEMINI_MAX_RETRIES + 1):
        if check_cancel and check_cancel():
            return ""
        uploaded = None
        try:
            if attempt == 1:
                logger(f"📎 正在把章节 PDF 上传给 Gemini（model={resolved_model}）：{os.path.basename(pdf_path)}")
            else:
                logger(f"🔁 Gemini PDF 直传第 {attempt}/{GEMINI_MAX_RETRIES} 次重试...")
            client = build_gemini_client_with_key(genai, api_key, types)
            with AsciiUploadCopy(pdf_path, suffix=".pdf", logger=logger) as upload_file:
                try:
                    uploaded = client.files.upload(file=upload_file.path, config={"mime_type": "application/pdf", "display_name": upload_file.upload_name})

                except TypeError:
                    uploaded = client.files.upload(file=upload_file.path)
            if types is not None:
                config = types.GenerateContentConfig(
                    system_instruction=system_instruction,
                    temperature=0.3,
                    max_output_tokens=GEMINI_TEXT_MAX_OUTPUT_TOKENS,
                )
                response = client.models.generate_content(
                    model=resolved_model,
                    contents=[uploaded, prompt],
                    config=config,
                )
            else:
                response = client.models.generate_content(
                    model=resolved_model,
                    contents=[uploaded, f"{system_instruction}\n\n{prompt}"],
                )
            result = (getattr(response, "text", "") or "").strip()
            if result:
                clear_gemini_failure()
                logger("✅ Gemini 已完成 PDF 附件直读生成。")
                return result
            raise RuntimeError("Gemini PDF 直传返回为空文本")
        except Exception as e:
            err = str(e)
            last_err = err
            if is_gemini_unsupported_location_error(e):
                set_gemini_failure("unsupported_location", err)
                log_gemini_unsupported_location(logger, task_name="Gemini PDF 直传")
                return ""
            if is_non_retryable_gemini_error(e):
                set_gemini_failure("non_retryable", err)
                logger(f"❌ Gemini PDF 直传返回不可重试错误：{err[:180]}")
                return ""
            set_gemini_failure("retryable", err)
            if attempt < GEMINI_MAX_RETRIES:
                wait_s = compute_gemini_backoff_seconds(attempt)
                if "ascii" in err.lower() and "encode" in err.lower():
                    logger("⚠️ 检测到 ASCII 编码上传错误，已自动改用 ASCII 临时文件名重试。")
                logger(f"⚠️ Gemini PDF 直传失败：{err[:120]}；{wait_s:.0f}s 后自动重试。")
                time.sleep(wait_s)
                continue
            logger(f"❌ Gemini PDF 直传连续失败：{err[:180]}")
            break
    logger(f"建议：切换 GPT-5.5 / Gemini 3.5 Flash / Gemini 3.1 Pro，或改用网页手动上传章节 PDF。最后错误：{last_err[:160]}")
    return ""


GeminiApiClient.generate_text_with_pdf = staticmethod(_gemini_generate_text_with_pdf)



class OpenAITextClient:
    """基于 OpenAI Responses API 的 GPT-5.5 文本生成客户端。

    默认模型 ID 明示为 gpt-5.5；如 OpenAI 官方后续更新，可通过环境变量
    OPENAI_TEXT_MODEL 覆盖，但日志和界面仍会显示实际使用的模型 ID。
    """

    MODEL_NAME = os.environ.get("OPENAI_TEXT_MODEL", "gpt-5.5")

    @staticmethod
    def generate_text(api_key: str, prompt: str, logger, check_cancel=None, model_name: str = "") -> str:
        api_key = sanitize_openai_api_key(api_key)
        if not is_valid_openai_api_key(api_key):
            logger("❌ OpenAI API Key 格式不正确：请确认只粘贴 OPENAI_API_KEY，不要包含 Bearer、空格、换行或多余字符。")
            return ""
        if check_cancel and check_cancel():
            return ""
        try:
            from openai import OpenAI
        except Exception:
            logger("❌ 缺少 openai 依赖。请先运行：pip install openai")
            return ""
        try:
            requested_model = str(model_name or "").strip()
            resolved_model = requested_model or OpenAITextClient.MODEL_NAME
            if "openai_model_for_text_engine" in globals():
                resolved_model = openai_model_for_text_engine(requested_model) if requested_model else OpenAITextClient.MODEL_NAME
            logger(f"🌐 正在通过中转站请求 OpenAI {resolved_model}...")
            client = OpenAI(api_key=api_key, base_url=foreign_model_base_url(), timeout=600, max_retries=2)
            system_instruction = ""
            response = client.responses.create(
                model=resolved_model,
                reasoning={"effort": OPENAI_REASONING_EFFORT},
                instructions=system_instruction,
                input=prompt,
                max_output_tokens=OPENAI_TEXT_MAX_OUTPUT_TOKENS,
            )
            if check_cancel and check_cancel():
                return ""
            return _extract_response_text(response)
        except Exception as e:
            logger(f"❌ OpenAI 文本请求出错: {str(e)[:180]}")
            return ""


# 给 OpenAI Responses 增加 PDF 附件直传能力。
def _openai_generate_text_with_pdf(api_key: str, prompt: str, pdf_path: str, logger, check_cancel=None, model_name: str = "") -> str:
    api_key = sanitize_openai_api_key(api_key)
    if not is_valid_openai_api_key(api_key):
        logger("❌ OpenAI API Key 格式不正确，无法上传 PDF。")
        return ""
    if not pdf_path or not os.path.exists(pdf_path):
        logger("❌ OpenAI PDF 直传失败：章节 PDF 文件不存在。")
        return ""
    if check_cancel and check_cancel():
        return ""
    try:
        from openai import OpenAI
    except Exception:
        logger("❌ 缺少 openai 依赖。请先运行：pip install openai")
        return ""
    uploaded_file_id = ""
    try:
        requested_model = str(model_name or "").strip()
        resolved_model = requested_model or OpenAITextClient.MODEL_NAME
        if "openai_model_for_text_engine" in globals():
            resolved_model = openai_model_for_text_engine(requested_model) if requested_model else OpenAITextClient.MODEL_NAME
        logger(f"📎 正在通过中转站把章节 PDF 上传给 OpenAI（model={resolved_model}）：{os.path.basename(pdf_path)}")
        client = OpenAI(api_key=api_key, base_url=foreign_model_base_url(), timeout=600)
        with AsciiUploadCopy(pdf_path, suffix=".pdf", logger=logger) as upload_file:
            with open(upload_file.path, "rb") as f:
                try:
                    uploaded = client.files.create(file=(upload_file.upload_name, f, "application/pdf"), purpose=OPENAI_PDF_UPLOAD_PURPOSE)
                except TypeError:
                    f.seek(0)
                    uploaded = client.files.create(file=f, purpose=OPENAI_PDF_UPLOAD_PURPOSE)
        uploaded_file_id = getattr(uploaded, "id", "") or ""
        if not uploaded_file_id:
            logger("❌ OpenAI PDF 上传后未返回 file_id。")
            return ""
        system_instruction = ""
        response = client.responses.create(
            model=resolved_model,
            reasoning={"effort": OPENAI_REASONING_EFFORT},
            instructions=system_instruction,
            input=[
                {
                    "role": "user",
                    "content": [
                        {"type": "input_file", "file_id": uploaded_file_id},
                        {"type": "input_text", "text": prompt},
                    ],
                },
            ],
            max_output_tokens=OPENAI_TEXT_MAX_OUTPUT_TOKENS,
        )
        if check_cancel and check_cancel():
            return ""
        result = _extract_response_text(response)
        if result:
            logger("✅ OpenAI 已完成 PDF 附件直读生成。")
        else:
            logger("⚠️ OpenAI PDF 直传返回为空文本。")
        return result
    except Exception as e:
        err = str(e)
        if "ascii" in err.lower() and "encode" in err.lower():
            logger("❌ OpenAI PDF 直传遇到 ASCII 编码问题：通常来自中文路径/文件名。v85 已自动使用 ASCII 临时文件名；如果仍出现，请把 PDF 放到纯英文路径后重试。")
        logger(f"❌ OpenAI PDF 直传请求出错: {err[:220]}")
        logger("建议：确认当前 OpenAI 模型支持 PDF 文件输入；当前版本已移除 MinerU 解析回退。")
        return ""


OpenAITextClient.generate_text_with_pdf = staticmethod(_openai_generate_text_with_pdf)


# ---------------------------------------------------------------------------
# Image-safety guardrails for scientific diagrams
# ---------------------------------------------------------------------------
def _compact_prompt_text_for_log(text: str, limit: int = 220) -> str:
    text = re.sub(r"\s+", " ", str(text or "")).strip()
    return text[:limit]


def _image_exception_text(exc: Exception) -> str:
    """Return a useful one-line OpenAI/compatible image error message."""
    parts = [str(exc or "")]
    try:
        resp = getattr(exc, "response", None)
        if resp is not None:
            status = getattr(resp, "status_code", "") or getattr(resp, "status", "")
            body = ""
            try:
                body = resp.text
            except Exception:
                body = ""
            if status or body:
                parts.append(f"HTTP {status} {body[:500]}")
    except Exception:
        pass
    try:
        request_id = getattr(exc, "request_id", "") or getattr(exc, "x_request_id", "")
        if request_id:
            parts.append(f"request_id={request_id}")
    except Exception:
        pass
    return " | ".join([p for p in parts if p])


def _is_retryable_image_error(exc: Exception) -> bool:
    text = _image_exception_text(exc).lower()
    retry_keywords = [
        "rate limit",
        "input-images per min",
        "please try again",
        "too many requests",
        "429",
        "502",
        "503",
        "504",
        "bad gateway",
        "gateway timeout",
        "service unavailable",
        "timeout",
        "timed out",
        "temporarily unavailable",
        "connection error",
        "api connection",
        "connection aborted",
        "connection reset",
        "server disconnected",
        "remote protocol error",
        "read error",
    ]
    return any(k in text for k in retry_keywords)


def _is_image_safety_rejection(exc: Exception) -> bool:
    low = _image_exception_text(exc).lower()
    return (
        "safety system" in low
        or "safety" in low and "rejected" in low
        or "your request was rejected" in low
        or "content_policy" in low
        or "content policy" in low
        or "policy_violation" in low
    )


def _rewrite_prompt_as_safe_science_diagram(prompt: str, role: str = "") -> str:
    """Keep the scientific idea, but remove graphic accident/injury scene wording.

    This is for educational neuroscience/science diagrams. It deliberately turns
    injury examples into abstract receptor/pathway diagrams before calling GPT Image 2,
    because literal accident or body-harm wording can be blocked even when the
    intended output is scientific.
    """
    text = str(prompt or "")
    if not text.strip():
        return text

    # Replace common body-harm examples with abstract mechanistic wording.
    replacements = [
        (r"锤子\s*(?:砸|敲|击|撞|打)\s*(?:到|中)?\s*(?:拇指|手指|指尖|手部|手)", "机械刺激作用于指尖的抽象示意"),
        (r"(?:拇指|手指|指尖|手部|手)\s*被\s*(?:锤子|铁锤|榔头)\s*(?:砸|敲|击|撞|打)", "指尖受到机械刺激的抽象示意"),
        (r"(?:hammer|mallet)\s+(?:hits|strikes|smashes|crushes)\s+(?:a\s+)?(?:thumb|finger|hand|fingertip)", "abstract mechanical stimulus applied to a fingertip receptor field"),
        (r"(?:thumb|finger|hand|fingertip)\s+(?:hit|struck|smashed|crushed)\s+by\s+(?:a\s+)?(?:hammer|mallet)", "abstract mechanical stimulus applied to a fingertip receptor field"),
        (r"\b(?:hammer|mallet)\b", "mechanical stimulus icon"),
        (r"锤子|铁锤|榔头", "机械刺激图标"),
        (r"(?:流血|出血|血淋淋|血迹|伤口|创口|淤青|骨折|砸伤|创伤|外伤|撕裂|断裂|破裂)", "组织受刺激的抽象标记"),
        (r"\b(?:blood|bleeding|bloody|gore|gory|wound|bruising|bruise|fracture|trauma|injury|injured|crush injury|cut|laceration)\b", "abstract tissue stimulus marker"),
        (r"(?:痛苦表情|疼得|尖叫|哭喊|受害者|事故现场)", "中性生理反应示意"),
        (r"\b(?:screaming|victim|accident scene|facial expression of pain)\b", "neutral physiological schematic"),
    ]
    for pat, repl in replacements:
        text = re.sub(pat, repl, text, flags=re.I)

    # For nociception/pain chapters, steer to pathway diagrams rather than scenes.
    if re.search(r"疼痛|痛觉|伤害感受器|nocicept|nociception|pain", text, flags=re.I):
        text = re.sub(r"伤害感受器", "nociceptors（伤害性感受器）", text)
        text = re.sub(r"疼痛信号|痛觉信号", "nociceptive signal pathway", text)
        text = re.sub(r"疼痛", "nociceptive signaling", text)
        text += (
            "\n\nOpenAI image safety rewrite: create a neutral educational neuroscience diagram. "
            "Show abstract nociceptors, sensory afferent fibers, spinal cord relay, and brain pathway as simplified anatomical/diagrammatic forms. "
            "Use diagram-only visual language: receptor fields, fibers, relay nodes, and signal arrows; no realistic human scene. "
            "Use clean schematic composition, soft editorial biomedical style, and no sensational scene."
        )
    else:
        text += (
            "\n\nOpenAI image safety rewrite: keep this as a neutral educational science diagram. "
            "Avoid sensational scenes; prefer abstract mechanisms, simplified anatomy, clean pathways, and non-graphic editorial illustration."
        )

    # Limit runaway prompts after adding safety rewrite.
    if len(text) > 11000:
        text = text[:11000].rstrip() + "\nNeutral educational science diagram; non-graphic schematic."
    return text.strip()


def _create_local_science_placeholder_image(save_path: str, prompt: str, logger=None) -> bool:
    """Last-resort local placeholder so one blocked image does not break a chapter."""
    try:
        from PIL import Image, ImageDraw, ImageFilter
        role = detect_visual_role(os.path.basename(save_path), prompt)
        _ratio, _size, w, h = visual_role_canvas(role)
        w = int(w or 720); h = int(h or 1280)
        os.makedirs(os.path.dirname(save_path), exist_ok=True)
        img = Image.new("RGB", (w, h), (236, 244, 250))
        overlay = Image.new("RGBA", (w, h), (255, 255, 255, 0))
        d = ImageDraw.Draw(overlay)
        # soft abstract biomedical pathway: receptors -> fiber -> relay nodes
        primary = (35, 77, 120, 155)
        secondary = (92, 135, 166, 115)
        pale = (255, 255, 255, 185)
        margin = int(w * 0.14)
        center_y = int(h * 0.50)
        # background bands
        for i in range(5):
            y = int(h * (0.18 + i * 0.13))
            d.rounded_rectangle((margin, y, w - margin, y + int(h * 0.055)), radius=int(w*0.035), fill=(255,255,255,42))
        # receptors/cells
        pts = [
            (int(w*0.22), int(h*0.62)),
            (int(w*0.38), int(h*0.55)),
            (int(w*0.55), int(h*0.47)),
            (int(w*0.72), int(h*0.39)),
        ]
        for i in range(len(pts)-1):
            d.line([pts[i], pts[i+1]], fill=primary, width=max(3, int(w*0.01)))
        for idx,(x,y) in enumerate(pts):
            r = int(w*(0.055 if idx in (0,3) else 0.046))
            d.ellipse((x-r, y-r, x+r, y+r), fill=pale, outline=primary, width=max(2, int(w*0.006)))
            inner = int(r*0.45)
            d.ellipse((x-inner, y-inner, x+inner, y+inner), fill=secondary)
        # signal arcs
        for k in range(4):
            x0 = int(w*(0.16 + k*0.16)); y0 = int(h*(0.27 + k*0.03))
            x1 = x0 + int(w*0.18); y1 = y0 + int(h*0.16)
            d.arc((x0,y0,x1,y1), start=205, end=345, fill=secondary, width=max(2,int(w*0.004)))
        overlay = overlay.filter(ImageFilter.GaussianBlur(radius=0.2))
        img = Image.alpha_composite(img.convert("RGBA"), overlay).convert("RGB")
        img.save(save_path, "PNG")
        if logger:
            logger(f"🛡️ 已生成本地安全占位科学示意图，避免安全拦截中断流程：{save_path}")
        try:
            postprocess_generated_image(save_path, prompt, logger, prompt_name=os.path.basename(save_path))
        except Exception:
            pass
        return True
    except Exception as e:
        if logger:
            logger(f"⚠️ 本地安全占位图生成失败：{str(e)[:120]}")
        return False



class OpenAIImageClient:
    """基于 OpenAI Image API 的 GPT Image 2 配图客户端。

    默认图像模型 ID 明示为 gpt-image-2。这里不再用主线 GPT 模型的
    Responses API image_generation 工具代替绘图模型，而是直接调用
    /v1/images/generations 对应的 GPT Image 模型。
    """

    MODEL_NAME = os.environ.get("OPENAI_IMAGE_MODEL", "gpt-image-2")
    DEFAULT_SIZE_27_48 = os.environ.get("OPENAI_IMAGE_SIZE_27_48", "720x1280")
    DEFAULT_SIZE_27_36 = os.environ.get("OPENAI_IMAGE_SIZE_27_36", "720x960")
    DEFAULT_QUALITY = os.environ.get("OPENAI_IMAGE_QUALITY", "low")

    @staticmethod
    def _extract_image_bytes(response) -> bytes:
        data = getattr(response, "data", None) or []
        if not data:
            return b""
        first = data[0]
        b64_json = getattr(first, "b64_json", None)
        if b64_json:
            return base64.b64decode(b64_json)

        image_url = getattr(first, "url", None)
        if image_url:
            r = requests.get(image_url, timeout=180)
            r.raise_for_status()
            return r.content
        return b""

    @staticmethod
    def generate_image(api_key: str, prompt: str, save_path: str, logger, check_cancel=None) -> bool:
        api_key = sanitize_openai_api_key(api_key)
        if not is_valid_openai_api_key(api_key):
            logger("❌ OpenAI API Key 缺失或格式不正确：使用 GPT Image 2 生成配图需要 OPENAI_API_KEY。")
            return False
        if check_cancel and check_cancel():
            return False
        try:
            from openai import OpenAI
        except Exception:
            logger("❌ 缺少 openai 依赖。请先运行：pip install openai")
            return False
        try:
            role = detect_visual_role(os.path.basename(save_path), prompt)
            target_ratio, target_size, req_w, req_h = detect_visual_canvas_from_prompt(prompt)
            target_ratio, target_size, req_w, req_h = coerce_openai_image_request_size(role, target_size, req_w, req_h)
            logger(
                f"🎨 正在请求 OpenAI GPT Image 2 图像模型 "
                f"(model={OpenAIImageClient.MODEL_NAME}, role={role}, ratio={target_ratio}, request_size={target_size}, quality={OpenAIImageClient.DEFAULT_QUALITY})..."
            )
            client = OpenAI(api_key=api_key, base_url=foreign_model_base_url(), timeout=600, max_retries=0)
            raw_prompt = str(prompt or "").strip()
            full_prompt = _rewrite_prompt_as_safe_science_diagram(raw_prompt, role=role)
            if full_prompt != raw_prompt:
                logger("🛡️ 已对 OpenAI 图像提示词做科学插图安全化处理：保留机制，移除事故/受伤场景措辞。")
            compact_safe_prompt = (
                "Neutral educational neuroscience diagram for a science-book explanation. "
                "Use abstract receptors, neurons, pathways, tissue layers, signal flow, and clean editorial biomedical illustration. "
                "Use diagram-only visual language; avoid people, photorealistic scenes, sensational drama, and realistic distress. "
                "No visible text, no labels, no captions; software will add overlays later."
            )
            def _request_image(prompt_text: str):
                delays = [0, 20, 45, 90, 150]
                last_error = None
                for attempt, wait_s in enumerate(delays, start=1):
                    if check_cancel and check_cancel():
                        return None
                    if wait_s:
                        logger(f"⏳ GPT Image 2 临时连接/网关错误，等待 {wait_s} 秒后重试（第 {attempt}/{len(delays)} 次）。")
                        time.sleep(wait_s)
                    try:
                        return client.images.generate(
                            model=OpenAIImageClient.MODEL_NAME,
                            prompt=prompt_text,
                            size=target_size,
                            quality=OpenAIImageClient.DEFAULT_QUALITY,
                            n=1,
                        )
                    except Exception as err:
                        last_error = err
                        if _is_image_safety_rejection(err) or not _is_retryable_image_error(err) or attempt >= len(delays):
                            raise err
                        logger(f"⚠️ GPT Image 2 请求遇到临时错误，准备重试：{_image_exception_text(err)[:260]}")
                if last_error:
                    raise last_error
                return None

            try:
                response = _request_image(full_prompt)
            except Exception as first_error:
                if _is_image_safety_rejection(first_error):
                    logger(f"🛡️ OpenAI 安全系统拦截了原配图提示词，准备使用更保守的抽象科学示意图重试；错误={_image_exception_text(first_error)[:260]}")
                    try:
                        response = _request_image(compact_safe_prompt)
                    except Exception as second_error:
                        if _is_image_safety_rejection(second_error):
                            logger(f"🛡️ OpenAI 第二次仍被安全系统拦截，未生成真实图；请调整提示词后补图。错误={_image_exception_text(second_error)[:260]}")
                            return False
                        raise second_error
                else:
                    raise first_error
            if check_cancel and check_cancel():
                return False
            img_bytes = OpenAIImageClient._extract_image_bytes(response)
            if not img_bytes:
                logger(f"⚠️ OpenAI GPT Image 2 未返回图片数据：model={OpenAIImageClient.MODEL_NAME}")
                return False
            os.makedirs(os.path.dirname(save_path), exist_ok=True)
            with open(save_path, "wb") as f:
                f.write(img_bytes)
            postprocess_generated_image(save_path, prompt, logger, prompt_name=os.path.basename(save_path))
            logger(f"✅ GPT Image 2 图片已保存：{save_path}；模型={OpenAIImageClient.MODEL_NAME}")
            return True
        except Exception as e:
            err_text = _image_exception_text(e)
            if _is_image_safety_rejection(e):
                logger(f"❌ OpenAI GPT Image 2 配图请求被安全系统拒绝，已尝试安全化重试但仍未生成真实图；错误={err_text[:320]}")
                return False
            logger(f"❌ OpenAI GPT Image 2 配图请求出错: {err_text[:320]}")
            return False


class GeminiBananaImageClient:
    """Gemini image models through NewAPI's native Gemini generateContent route."""

    DEFAULT_SIZE = os.environ.get("GEMINI_IMAGE_SIZE", "720x1280")

    @staticmethod
    def _extract_image_bytes(data) -> bytes:
        def _decode(value: str) -> bytes:
            text = str(value or "").strip()
            if not text:
                return b""
            if text.startswith("data:image"):
                text = text.split(",", 1)[-1]
            try:
                return base64.b64decode(text)
            except Exception:
                return b""

        def _walk(obj):
            if isinstance(obj, dict):
                inline = obj.get("inlineData") or obj.get("inline_data")
                if isinstance(inline, dict):
                    blob = inline.get("data") or inline.get("b64_json") or inline.get("base64")
                    img = _decode(blob)
                    if img:
                        return img
                for key in ("data", "b64_json", "base64", "image_base64"):
                    img = _decode(obj.get(key))
                    if img:
                        return img
                for value in obj.values():
                    img = _walk(value)
                    if img:
                        return img
            elif isinstance(obj, list):
                for value in obj:
                    img = _walk(value)
                    if img:
                        return img
            return b""

        return _walk(data)

    @staticmethod
    def generate_image(api_key: str, prompt: str, save_path: str, logger, check_cancel=None, *, model_name: str = "") -> bool:
        api_key = sanitize_gemini_api_key(api_key)
        if not is_valid_gemini_api_key(api_key):
            logger("❌ Gemini Key 缺失或格式不正确：使用 Gemini 图像模型需要 gemini_api_key.txt。")
            return False
        if check_cancel and check_cancel():
            return False
        try:
            role = detect_visual_role(os.path.basename(save_path), prompt)
            target_ratio, target_size, req_w, req_h = detect_visual_canvas_from_prompt(prompt)
            target_ratio, target_size, req_w, req_h = coerce_openai_image_request_size(role, target_size, req_w, req_h)
            model = str(model_name or GEMINI_IMAGE_ENGINE_MODEL_MAP.get(IMAGE_ENGINE_GEMINI_31_FLASH) or "gemini-3.1-flash-image-preview").strip()
            base = foreign_model_base_url().rsplit("/v1", 1)[0].rstrip("/")
            url = f"{base}/v1beta/models/{model}:generateContent"
            logger(f"🎨 正在请求 Gemini 原生生图接口 (model={model}, role={role}, ratio={target_ratio}, request_size={target_size})...")
            payload = {
                "contents": [
                    {
                        "role": "user",
                        "parts": [{"text": str(prompt or "").strip()}],
                    }
                ],
                "generationConfig": {
                    "responseModalities": ["TEXT", "IMAGE"],
                },
            }
            headers = {
                "Content-Type": "application/json",
                "Authorization": f"Bearer {api_key}",
            }
            response = requests_post_no_proxy(
                url,
                headers=headers,
                json=payload,
                timeout=300,
            )
            response.raise_for_status()
            data = response.json()
            if check_cancel and check_cancel():
                return False
            img_bytes = GeminiBananaImageClient._extract_image_bytes(data)
            if not img_bytes:
                logger(f"⚠️ Gemini 原生生图未返回图片数据：model={model}")
                return False
            os.makedirs(os.path.dirname(save_path), exist_ok=True)
            with open(save_path, "wb") as f:
                f.write(img_bytes)
            postprocess_generated_image(save_path, prompt, logger, prompt_name=os.path.basename(save_path))
            logger(f"✅ Gemini 原生生图已保存：{save_path}；模型={model}")
            return True
        except Exception as e:
            logger(f"❌ Gemini 原生生图请求出错: {_image_exception_text(e)[:320]}")
            return False


class ChatShareTextClient:
    """基于 ChatShare OpenAI-compatible Chat Completions API 的文本生成客户端。"""

    BASE_URL = os.environ.get("CHATSHARE_API_BASE", foreign_model_base_url()).rstrip("/")
    MODEL_NAME = os.environ.get("CHATSHARE_TEXT_MODEL", "gpt-5-pro")

    @staticmethod
    def generate_text(api_key: str, prompt: str, logger, check_cancel=None, model_name: str = "") -> str:
        api_key = sanitize_chatshare_api_key(api_key)
        if not is_valid_chatshare_api_key(api_key):
            logger("❌ ChatShare API Key 格式不正确：请确认只粘贴 ChatShare Key，不要包含 Bearer、空格、换行或多余字符。")
            return ""
        if check_cancel and check_cancel():
            return ""
        model_name = str(model_name or ChatShareTextClient.MODEL_NAME).strip() or ChatShareTextClient.MODEL_NAME
        system_instruction = ""
        url = f"{ChatShareTextClient.BASE_URL}/chat/completions"
        payload = {
            "model": model_name,
            "messages": [
                {"role": "system", "content": system_instruction},
                {"role": "user", "content": prompt},
            ],
            "temperature": 0.7,
            "max_tokens": CHATSHARE_TEXT_MAX_OUTPUT_TOKENS,
        }
        headers = {"Content-Type": "application/json", "Authorization": f"Bearer {api_key}"}
        try:
            logger(f"🌐 正在请求 ChatShare {model_name}...")
            resp = requests.post(url, headers=headers, json=payload, timeout=300)
            resp.raise_for_status()
            data = resp.json()
            if check_cancel and check_cancel():
                return ""
            choices = data.get("choices") or []
            if choices:
                msg = choices[0].get("message") or {}
                content = msg.get("content") or choices[0].get("text") or ""
                if isinstance(content, list):
                    content = "".join([part.get("text", "") if isinstance(part, dict) else str(part) for part in content])
                return str(content).strip()
            return str(data.get("output_text", "") or data.get("text", "")).strip()
        except Exception as e:
            logger(f"❌ ChatShare 文本请求出错: {str(e)[:180]}")
            return ""


