class ChatShareImageClient:
    """基于 ChatShare OpenAI-compatible 图像接口的 GPT Image 2 配图客户端。"""

    BASE_URL = os.environ.get("CHATSHARE_API_BASE", foreign_model_base_url()).rstrip("/")
    MODEL_NAME = os.environ.get("CHATSHARE_IMAGE_MODEL", "gpt-image-2")
    DEFAULT_QUALITY = os.environ.get("CHATSHARE_IMAGE_QUALITY", os.environ.get("OPENAI_IMAGE_QUALITY", "low"))

    @staticmethod
    def _extract_image_bytes(data) -> bytes:
        def _decode_or_fetch(value: str) -> bytes:
            if not value:
                return b""
            value = str(value).strip()
            if value.startswith("data:image") and "," in value:
                value = value.split(",", 1)[1]
            if value.startswith("http"):
                r = requests.get(value, timeout=180)
                r.raise_for_status()
                return r.content
            try:
                return base64.b64decode(value)
            except Exception:
                return b""

        if isinstance(data, dict):
            items = data.get("data") or []
            if items:
                first = items[0] or {}
                for key in ("b64_json", "base64", "image_base64", "url", "image_url"):
                    img = _decode_or_fetch(first.get(key, ""))
                    if img:
                        return img
            for key in ("result", "image", "b64_json", "base64", "url"):
                img = _decode_or_fetch(data.get(key, ""))
                if img:
                    return img
            choices = data.get("choices") or []
            for choice in choices:
                msg = choice.get("message") or {}
                content = msg.get("content") or choice.get("text") or ""
                if isinstance(content, list):
                    for part in content:
                        if isinstance(part, dict):
                            for key in ("b64_json", "base64", "image_base64", "url", "image_url", "text"):
                                img = _decode_or_fetch(part.get(key, ""))
                                if img:
                                    return img
                elif isinstance(content, str):
                    # Try markdown image URLs or raw URL/base64 returned by OpenAI-compatible gateways.
                    m = re.search(r'!\[[^\]]*\]\((https?://[^)]+)\)', content) or re.search(r'(https?://\S+)', content)
                    if m:
                        img = _decode_or_fetch(m.group(1))
                        if img:
                            return img
                    img = _decode_or_fetch(content)
                    if img:
                        return img
        return b""

    @staticmethod
    def generate_image(api_key: str, prompt: str, save_path: str, logger, check_cancel=None) -> bool:
        api_key = sanitize_chatshare_api_key(api_key)
        if not is_valid_chatshare_api_key(api_key):
            logger("❌ ChatShare API Key 缺失或格式不正确：使用 ChatShare GPT Image 2 生成配图需要 ChatShare Key。")
            return False
        if check_cancel and check_cancel():
            return False
        role = detect_visual_role(os.path.basename(save_path), prompt)
        target_ratio, target_size, _, _ = detect_visual_canvas_from_prompt(prompt)
        raw_prompt = str(prompt or "").strip()
        full_prompt = _rewrite_prompt_as_safe_science_diagram(raw_prompt, role=role)
        if full_prompt != raw_prompt:
            logger("🛡️ 已对 ChatShare 图像提示词做科学插图安全化处理：保留机制，移除事故/受伤场景措辞。")
        url = f"{ChatShareImageClient.BASE_URL}/images/generations"
        payload = {
            "model": ChatShareImageClient.MODEL_NAME,
            "prompt": full_prompt,
            "size": target_size,
            "quality": ChatShareImageClient.DEFAULT_QUALITY,
            "n": 1,
        }
        headers = {"Content-Type": "application/json", "Authorization": f"Bearer {api_key}"}
        try:
            logger(
                f"🎨 正在请求 ChatShare GPT Image 2 图像模型 "
                f"(model={ChatShareImageClient.MODEL_NAME}, ratio={target_ratio}, size={target_size}, quality={ChatShareImageClient.DEFAULT_QUALITY})..."
            )
            try:
                try:
                    resp = requests.post(url, headers=headers, json=payload, timeout=300)
                    resp.raise_for_status()
                    data = resp.json()
                except Exception as image_endpoint_error:
                    if _is_image_safety_rejection(image_endpoint_error):
                        logger(f"🛡️ ChatShare 图像入口被安全系统拦截，改用更保守的抽象科学示意图提示词重试；错误={_image_exception_text(image_endpoint_error)[:220]}")
                        payload["prompt"] = (
                            "Neutral educational neuroscience diagram. Abstract receptors, neurons, pathways, tissue layers, and signal flow. "
                            "Clean editorial biomedical illustration; diagram-only visual language; avoid people, photorealistic scenes, realistic distress, visible text, labels, or captions."
                        )
                        resp = requests.post(url, headers=headers, json=payload, timeout=300)
                        resp.raise_for_status()
                        data = resp.json()
                    else:
                        logger(f"⚠️ ChatShare /images/generations 未成功：{_image_exception_text(image_endpoint_error)[:160]}；尝试使用 /chat/completions 兼容入口。")
                        chat_payload = {
                            "model": ChatShareImageClient.MODEL_NAME,
                            "messages": [{"role": "user", "content": full_prompt}],
                            "temperature": 0.2,
                        }
                        chat_resp = requests.post(f"{ChatShareImageClient.BASE_URL}/chat/completions", headers=headers, json=chat_payload, timeout=300)
                        chat_resp.raise_for_status()
                        data = chat_resp.json()
            except Exception as retry_error:
                if _is_image_safety_rejection(retry_error):
                    logger(f"🛡️ ChatShare 第二次仍被安全系统拦截，未生成真实图；将交由当前流程标记为待补图。错误={_image_exception_text(retry_error)[:240]}")
                    return False
                raise retry_error
            if check_cancel and check_cancel():
                return False
            img_bytes = ChatShareImageClient._extract_image_bytes(data)
            if not img_bytes:
                logger(f"⚠️ ChatShare GPT Image 2 未返回图片数据：model={ChatShareImageClient.MODEL_NAME}")
                return False
            os.makedirs(os.path.dirname(save_path), exist_ok=True)
            with open(save_path, "wb") as f:
                f.write(img_bytes)
            postprocess_generated_image(save_path, prompt, logger, prompt_name=os.path.basename(save_path))
            logger(f"✅ ChatShare GPT Image 2 图片已保存：{save_path}；模型={ChatShareImageClient.MODEL_NAME}")
            return True
        except Exception as e:
            err_text = _image_exception_text(e)
            if _is_image_safety_rejection(e):
                logger(f"❌ ChatShare GPT Image 2 配图请求被安全系统拒绝，已尝试安全化重试但仍未生成真实图；错误={err_text[:320]}")
                return False
            logger(f"❌ ChatShare GPT Image 2 配图请求出错: {err_text[:320]}")
            return False


class DoubaoArkTextClient:
    """豆包 API（火山方舟 Ark）OpenAI-compatible Chat Completions 客户端。

    注意：model 必须填写火山方舟推理接入点 ID（通常 ep- 开头）。
    本客户端只发送文本；PDF 文件不会上传给豆包。
    """

    BASE_URL = DOUBAO_API_BASE_URL
    DEFAULT_TEMPERATURE = float(os.environ.get("DOUBAO_TEXT_TEMPERATURE", "0.45") or 0.45)
    # Ark 不同 Endpoint 的输出上限不完全一致。默认 4096 更稳；需要长输出可用环境变量覆盖。
    MAX_OUTPUT_TOKENS = int(os.environ.get("DOUBAO_TEXT_MAX_OUTPUT_TOKENS", "4096") or 4096)

    @staticmethod
    def _safe_error_body(resp) -> str:
        """返回可打印的 Ark 错误正文，不泄露 Authorization。"""
        try:
            body = resp.text or ""
        except Exception:
            body = ""
        body = str(body).strip().replace("\r", " ").replace("\n", " ")
        if len(body) > 800:
            body = body[:800] + "..."
        return body

    @staticmethod
    def _log_http_error(resp, logger, prefix: str = "豆包 Ark"):
        try:
            status = getattr(resp, "status_code", "")
            logid = resp.headers.get("x-tt-logid") or resp.headers.get("X-Tt-Logid") or resp.headers.get("x-request-id") or resp.headers.get("X-Request-Id") or ""
        except Exception:
            status, logid = "", ""
        body = DoubaoArkTextClient._safe_error_body(resp)
        if logger:
            msg = f"❌ {prefix} HTTP {status}"
            if logid:
                msg += f"；logid={logid}"
            if body:
                msg += f"；响应={body}"
            logger(msg[:1200])

    @staticmethod
    def _post_chat(url: str, headers: dict, payload: dict, timeout: int = 300):
        return requests.post(url, headers=headers, json=payload, timeout=timeout)

    @staticmethod
    def generate_text(api_key: str, prompt: str, logger, check_cancel=None, model_name: str = "") -> str:
        api_key = sanitize_doubao_api_key(api_key or load_doubao_api_key())
        endpoint_id = sanitize_doubao_endpoint_id(model_name or load_doubao_endpoint_id())
        if not is_valid_doubao_api_key(api_key):
            logger("❌ 豆包 Ark API Key 格式不正确：请填写 ark- 开头的火山方舟 API Key。")
            return ""
        if not is_valid_doubao_endpoint_id(endpoint_id):
            logger("❌ 豆包 Ark 推理接入点 ID 缺失或格式不正确：必须是 ep- 开头、仅含英文/数字/下划线/连字符的 Endpoint ID；不要填写“ep-请填写推理接入点ID”这类占位文字。")
            return ""
        if check_cancel and check_cancel():
            return ""

        url = f"{DoubaoArkTextClient.BASE_URL}/chat/completions"
        headers = {"Content-Type": "application/json", "Authorization": f"Bearer {api_key}"}
        base_messages = [
            {"role": "system", "content": "你是一名严谨、自然、通俗的中文科学旁白编辑。只依据用户提供的文本工作。"},
            {"role": "user", "content": prompt},
        ]
        max_tokens = max(256, min(int(DoubaoArkTextClient.MAX_OUTPUT_TOKENS or 4096), 8192))
        payload = {
            "model": endpoint_id,
            "messages": base_messages,
            "temperature": DoubaoArkTextClient.DEFAULT_TEMPERATURE,
            "max_tokens": max_tokens,
            "stream": False,
        }
        try:
            logger(f"🌐 正在请求豆包 Ark 文本模型：{endpoint_id}；max_tokens={max_tokens}...")
            resp = DoubaoArkTextClient._post_chat(url, headers, payload, timeout=300)

            # 常见 400 原因之一是 Endpoint 输出上限较低；先打印错误正文，再自动降级重试。
            if resp.status_code == 400:
                DoubaoArkTextClient._log_http_error(resp, logger)
                body = DoubaoArkTextClient._safe_error_body(resp).lower()
                retry_payloads = []
                if "max_tokens" in body or "max token" in body or "context" in body or "length" in body or max_tokens > 2048:
                    for smaller in (2048, 1024):
                        if smaller < max_tokens:
                            p2 = dict(payload)
                            p2["max_tokens"] = smaller
                            retry_payloads.append((f"降低 max_tokens 到 {smaller}", p2))
                # 个别 OpenAI-compatible 网关对 max_tokens 校验严格，最后尝试不传 max_tokens。
                p3 = dict(payload)
                p3.pop("max_tokens", None)
                retry_payloads.append(("不传 max_tokens", p3))

                for reason, p2 in retry_payloads:
                    if check_cancel and check_cancel():
                        return ""
                    logger(f"↻ 豆包 Ark 自动重试：{reason}...")
                    resp2 = DoubaoArkTextClient._post_chat(url, headers, p2, timeout=300)
                    if 200 <= resp2.status_code < 300:
                        resp = resp2
                        break
                    DoubaoArkTextClient._log_http_error(resp2, logger, prefix=f"豆包 Ark 重试失败（{reason}）")
                else:
                    return ""

            if not (200 <= resp.status_code < 300):
                DoubaoArkTextClient._log_http_error(resp, logger)
                return ""

            data = resp.json()
            if check_cancel and check_cancel():
                return ""
            text = _extract_openai_compatible_text_response(data)
            if not text:
                logger(f"⚠️ 豆包 Ark 返回为空文本；原始响应={str(data)[:800]}")
            return text.strip()
        except requests.exceptions.RequestException as e:
            logger(f"❌ 豆包 Ark 文本请求网络/HTTP异常: {str(e)[:300]}")
            return ""
        except Exception as e:
            logger(f"❌ 豆包 Ark 文本请求出错: {str(e)[:300]}")
            return ""


