def _count_pdf_pages_quiet(pdf_path: str) -> int:
    try:
        from pypdf import PdfReader
        with open(pdf_path, "rb") as f:
            return len(PdfReader(f).pages)
    except Exception:
        return 0


def ensure_chapter_pdf_for_llm(source_pdf_path: str, chapter_pdf_path: str, page: int, end_page: int, logger) -> bool:
    """为直接上传给大模型准备章节 PDF。保存为稳定文件，避免临时文件被提前清理。

    修复点：旧版本如果曾经错误切出 1 页章节 PDF，断点续跑会直接复用这个非空文件。
    现在会按预期页数校验，发现页数明显不足就删除并重新切分。
    """
    try:
        expected_pages = max(1, int(end_page) - int(page))
    except Exception:
        expected_pages = 1
    if is_nonempty_file(chapter_pdf_path):
        existing_pages = _count_pdf_pages_quiet(chapter_pdf_path)
        if existing_pages >= max(1, min(expected_pages, max(1, expected_pages - 1))):
            return True
        try:
            os.remove(chapter_pdf_path)
        except Exception:
            pass
        logger(f"⚠️ 已发现旧章节 PDF 页数不足：现有 {existing_pages} 页，预期约 {expected_pages} 页；将重新切分。")
    try:
        os.makedirs(os.path.dirname(chapter_pdf_path), exist_ok=True)
        logger(f"📄 正在切出章节 PDF 供大模型直读：第 {page}-{end_page} 页（end 为下一章边界，不含 end 页）")
        PDFProcessor.split_pdf(source_pdf_path, chapter_pdf_path, page, end_page)
        if is_nonempty_file(chapter_pdf_path):
            actual_pages = _count_pdf_pages_quiet(chapter_pdf_path)
            if actual_pages <= 1 and expected_pages > 2:
                logger(f"⚠️ 章节 PDF 仅切出 {actual_pages} 页，但预期约 {expected_pages} 页；请检查目录书签层级/页码。")
            else:
                logger(f"✅ 章节 PDF 已准备：{os.path.basename(chapter_pdf_path)}（{actual_pages} 页）")
            return True
        logger("⚠️ 章节 PDF 切分后为空，无法直传给大模型。")
        return False
    except Exception as e:
        logger(f"⚠️ 章节 PDF 准备失败：{str(e)[:160]}")
        return False


def _local_pdf_markdown_char_limit(default: int = 180_000) -> int:
    try:
        return max(10_000, int(os.environ.get("QUANLAN_LOCAL_PDF_MARKDOWN_MAX_CHARS", str(default)) or default))
    except Exception:
        return default


def local_pdf_parse_before_upload_enabled() -> bool:
    """默认先本地解析 PDF，再把 Markdown 文本交给模型；只有解析失败才走 PDF 附件直传。"""
    return str(os.environ.get("QUANLAN_LOCAL_PDF_PARSE_FIRST", "1")).strip().lower() in {"1", "true", "yes", "y", "on"}


def _log_pdf_parse(logger, message: str) -> None:
    try:
        if logger:
            logger(message)
    except Exception:
        pass


def _safe_page_start(value) -> int:
    try:
        return max(1, int(value or 1))
    except Exception:
        return 1


def extract_pdf_text(pdf_path, max_chars: int | None = None, use_mineru: bool = False, *, original_start_page: int = 1, logger=None) -> str:
    """本地解析单个 PDF 文件为 Markdown/text。

    设计目的：主流程先切出章节 PDF，再只解析该章节，避免对整本书做 Markdown 解析。
    PyMuPDF4LLM 可用时优先输出 Markdown；失败时回退 pypdf 纯文本；两者都失败才返回空串。
    参数 use_mineru 仅为兼容旧调用保留，不再启用 MinerU。
    """
    limit = _local_pdf_markdown_char_limit(max_chars or 180_000)
    path = os.fspath(pdf_path) if pdf_path is not None else ""
    if not path or not os.path.exists(path):
        _log_pdf_parse(logger, "⚠️ 本地 PDF 解析失败：文件不存在。")
        return ""

    start_page = _safe_page_start(original_start_page)
    base = os.path.basename(path)

    try:
        import pymupdf4llm  # type: ignore
        _log_pdf_parse(logger, f"📄 使用 PyMuPDF4LLM 本地解析章节 PDF：{base}")
        md_text = pymupdf4llm.to_markdown(str(path)) or ""
        md_text = str(md_text).strip()
        if md_text:
            truncated = md_text[:limit]
            if len(md_text) > limit:
                truncated += f"\n\n[已截断：本章解析文本 {len(md_text):,} 字符，仅发送前 {limit:,} 字符]"
            marked = f"[PyMuPDF4LLM Markdown解析｜章节PDF：{base}｜原始起始页：{start_page}]\n\n{truncated}"
            _log_pdf_parse(logger, f"✅ PyMuPDF4LLM 本地解析完成：{len(md_text):,} 字符；本次只解析章节 PDF，不解析整本书。")
            return marked
        _log_pdf_parse(logger, "⚠️ PyMuPDF4LLM 未提取到文本，准备回退 pypdf。")
    except ImportError:
        _log_pdf_parse(logger, "⚠️ 未安装 pymupdf4llm；请运行：pip install pymupdf4llm pymupdf。当前回退 pypdf。")
    except Exception as e:
        _log_pdf_parse(logger, f"⚠️ PyMuPDF4LLM 解析异常，准备回退 pypdf：{str(e)[:160]}")

    try:
        from pypdf import PdfReader
        chunks: list[str] = []
        total = 0
        with open(path, "rb") as f:
            reader = PdfReader(f)
            for idx, page in enumerate(reader.pages, start=1):
                try:
                    page_text = page.extract_text() or ""
                except Exception:
                    page_text = ""
                page_text = str(page_text or "").strip()
                if not page_text:
                    continue
                block = f"\n\n[PDF Page {start_page + idx - 1}]\n{page_text}"
                chunks.append(block)
                total += len(block)
                if total >= limit:
                    chunks.append(f"\n\n[已截断：仅发送前 {limit:,} 字符]")
                    break
        text = "".join(chunks).strip()
        if text:
            _log_pdf_parse(logger, f"✅ pypdf 本地文本提取完成：约 {len(text):,} 字符。")
            return f"[pypdf 文本提取｜章节PDF：{base}｜原始起始页：{start_page}]\n{text}"
        _log_pdf_parse(logger, "⚠️ pypdf 也未提取到文本。")
        return ""
    except Exception as e:
        _log_pdf_parse(logger, f"⚠️ pypdf 文本提取失败：{str(e)[:160]}")
        return ""


def extract_chapter_pdf_markdown(chapter_pdf_path: str, md_path: str = "", *, original_start_page: int = 1, max_chars: int | None = None, logger=None) -> str:
    """读取/生成章节级 Markdown 缓存。缓存命中时不重复解析 PDF。"""
    try:
        if md_path and is_nonempty_file(md_path):
            cached = read_text_file(md_path).strip()
            if cached:
                _log_pdf_parse(logger, f"✅ 已复用章节本地解析缓存：{os.path.basename(md_path)}")
                return cached
    except Exception:
        pass

    text = extract_pdf_text(chapter_pdf_path, max_chars=max_chars, original_start_page=original_start_page, logger=logger)
    if text and md_path:
        try:
            os.makedirs(os.path.dirname(md_path), exist_ok=True)
            write_text_file(md_path, text + "\n")
            _log_pdf_parse(logger, f"📝 已保存章节本地解析 Markdown：{os.path.basename(md_path)}")
        except Exception as e:
            _log_pdf_parse(logger, f"⚠️ 保存章节 Markdown 缓存失败：{str(e)[:120]}")
    return text


def build_pdf_text_fallback_prompt(prompt: str, pdf_path, *, max_chars: int | None = None, original_start_page: int = 1, logger=None, extracted_text: str = "") -> str:
    extracted = str(extracted_text or "").strip() or extract_pdf_text(pdf_path, max_chars=max_chars, original_start_page=original_start_page, logger=logger)
    if not extracted:
        return str(prompt or "")
    prefix = "PyMuPDF4LLM Markdown" if "PyMuPDF4LLM" in extracted[:120] else "pypdf 文本提取"
    try:
        extracted_for_model = truncate_context(extracted, max_chars or SCRIPT_CONTEXT_CHAR_LIMIT)
    except Exception:
        extracted_for_model = str(extracted or "")[: int(max_chars or SCRIPT_CONTEXT_CHAR_LIMIT)]
    return f"{str(prompt or '').strip()}\n\n【本地解析后的章节内容｜{prefix}｜已自动精简去噪】\n{extracted_for_model}".strip()


def _try_replace_pdf_attachment_with_local_text(prompt: str, pdf_path: str, logger) -> tuple[str, str]:
    """若本地解析成功，返回追加 Markdown 后的 prompt，并清空 pdf_path，避免上传 PDF 附件。"""
    if not pdf_path or not local_pdf_parse_before_upload_enabled():
        return prompt, pdf_path
    local_text = extract_pdf_text(pdf_path, max_chars=_local_pdf_markdown_char_limit(), logger=logger)
    if local_text:
        new_prompt = build_pdf_text_fallback_prompt(prompt, pdf_path, extracted_text=local_text, logger=logger)
        _log_pdf_parse(logger, "✅ 已用本地解析 Markdown 替代 PDF 附件上传；本次文本请求不上传 PDF。")
        return new_prompt, ""
    _log_pdf_parse(logger, "❌ 本地解析没有可用文本；安全策略禁止上传 PDF 附件，本次文本请求停止。")
    return prompt, pdf_path


